import type { LibSQLDatabase } from 'drizzle-orm/libsql'
import { auditLogs } from './schema'
import type { WriteAuditLogParams } from './index'

// Duck-typed interface so we don't need @libsql/client as a runtime dependency
interface RawLibsqlClient {
  execute(stmt: { sql: string; args: (string | number | null)[] }): Promise<unknown>
}

/**
 * Write an audit log entry using a Drizzle ORM database instance.
 * Use this in SDK routes and Brain portal API routes.
 * Fire-and-forget — never throws, never blocks the main operation.
 */
export async function writeAuditLog(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  db: LibSQLDatabase<any>,
  params: WriteAuditLogParams,
): Promise<void> {
  try {
    await db.insert(auditLogs).values({
      id: globalThis.crypto.randomUUID(),
      actorType: params.actor.type,
      ...(params.actor.id != null && { actorId: params.actor.id }),
      ...(params.actor.email != null && { actorEmail: params.actor.email }),
      action: params.action,
      resourceType: params.resourceType,
      ...(params.resourceId != null && { resourceId: params.resourceId }),
      ...(params.traceId != null && { traceId: params.traceId }),
      ...(params.metadata != null && { metadata: JSON.stringify(params.metadata) }),
      createdAt: new Date(),
    })
  } catch {
    // Fire-and-forget: audit log failures must never block the main operation
  }
}

/**
 * Write an audit log entry using a raw @libsql/client Client instance.
 * Use this in worker jobs that use the raw libsql client directly.
 * Fire-and-forget — never throws, never blocks the main operation.
 */
export async function writeAuditLogRaw(
  client: RawLibsqlClient,
  params: WriteAuditLogParams,
): Promise<void> {
  try {
    const now = Math.floor(Date.now() / 1000)
    await client.execute({
      sql: `INSERT INTO audit_logs
            (id, actor_type, actor_id, actor_email, action, resource_type, resource_id, trace_id, metadata, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      args: [
        globalThis.crypto.randomUUID(),
        params.actor.type,
        params.actor.id ?? null,
        params.actor.email ?? null,
        params.action,
        params.resourceType,
        params.resourceId ?? null,
        params.traceId ?? null,
        params.metadata ? JSON.stringify(params.metadata) : null,
        now,
      ],
    })
  } catch {
    // Fire-and-forget: audit log failures must never block the main operation
  }
}
