import { eq, desc, and, or, count as drizzleCount } from 'drizzle-orm'
import type { SQLiteColumn } from 'drizzle-orm/sqlite-core'
import { blogAuthors, blogPosts, socialPosts } from '@growth-engine/types/schema'
import { getClientDb } from '../db'

const CACHE_HEADERS = {
	'Cache-Control': 's-maxage=60, stale-while-revalidate=300',
}

const BLOG_FIELDS_WHITELIST = new Set([
	'id', 'slug', 'urlPath', 'title', 'language', 'status',
	'updatedAt', 'createdAt', 'publishedAt', 'parentPostId',
	'heroImageUrl', 'seoTitle', 'seoDesc', 'authorId',
])

const DEFAULT_LIMIT = 20
const MAX_LIMIT = 5000

function parseBlogFields(fieldsParam: string | null) {
	if (!fieldsParam) return undefined

	const requested = fieldsParam.split(',').map((f) => f.trim()).filter(Boolean)
	const valid = requested.filter((f) => BLOG_FIELDS_WHITELIST.has(f))
	if (valid.length === 0) return undefined

	const selection: Record<string, SQLiteColumn> = {}
	for (const field of valid) {
		const col = blogPosts[field as keyof typeof blogPosts]
		if (col) selection[field] = col as SQLiteColumn
	}
	return Object.keys(selection).length > 0 ? selection : undefined
}

function parseLimit(limitParam: string | null): number {
	if (limitParam === null) return DEFAULT_LIMIT
	const n = parseInt(limitParam, 10)
	if (isNaN(n) || n < 0) return DEFAULT_LIMIT
	if (n === 0) return MAX_LIMIT
	return Math.min(n, MAX_LIMIT)
}

function parseOffset(offsetParam: string | null): number {
	if (offsetParam === null) return 0
	const n = parseInt(offsetParam, 10)
	return isNaN(n) || n < 0 ? 0 : n
}

export async function handleContent(
	request: Request,
	tursoUrl: string,
	tursoAuthToken: string,
): Promise<Response> {
	try {
		const url = new URL(request.url)
		const type = url.searchParams.get('type')
		const slug = url.searchParams.get('slug')
		const platform = url.searchParams.get('platform')
		const locale = url.searchParams.get('locale')

		const db = getClientDb(tursoUrl, tursoAuthToken)

		if (type === 'blog') {
			// Count-only mode for sitemap pagination
			const countOnly = url.searchParams.get('count') === 'true'
			if (countOnly) {
				const conditions = [eq(blogPosts.status, 'published')]
				if (locale) conditions.push(eq(blogPosts.language, locale))

				const result = await db
					.select({ count: drizzleCount() })
					.from(blogPosts)
					.where(and(...conditions))
				return Response.json(
					{ count: result[0]?.count ?? 0 },
					{ headers: CACHE_HEADERS },
				)
			}

			if (slug) {
				const slugMatch = or(eq(blogPosts.slug, slug), eq(blogPosts.urlPath, slug))
				const conditions = [slugMatch]
				if (locale) conditions.push(eq(blogPosts.language, locale))

				const post = await db
					.select()
					.from(blogPosts)
					.where(and(...conditions))
					.limit(1)
				return Response.json(post[0] ?? null, { headers: CACHE_HEADERS })
			}

			const authorSlug = url.searchParams.get('authorSlug')
			if (authorSlug) {
				const author = await db
					.select()
					.from(blogAuthors)
					.where(eq(blogAuthors.slug, authorSlug))
					.limit(1)
				if (!author[0]) {
					return Response.json([], { headers: CACHE_HEADERS })
				}

				const language = locale ?? 'en'
				const limit = parseLimit(url.searchParams.get('limit'))
				const offset = parseOffset(url.searchParams.get('offset'))
				const where = and(
					eq(blogPosts.status, 'published'),
					eq(blogPosts.language, language),
					eq(blogPosts.authorId, author[0].id),
				)

				const posts = await db
					.select()
					.from(blogPosts)
					.where(where)
					.orderBy(desc(blogPosts.createdAt))
					.limit(limit)
					.offset(offset)

				return Response.json(posts, { headers: CACHE_HEADERS })
			}

			const language = locale ?? 'en'
			const limit = parseLimit(url.searchParams.get('limit'))
			const offset = parseOffset(url.searchParams.get('offset'))
			const fields = parseBlogFields(url.searchParams.get('fields'))
			const where = and(
				eq(blogPosts.status, 'published'),
				eq(blogPosts.language, language),
			)

			const posts = fields
				? await db
						.select(fields)
						.from(blogPosts)
						.where(where)
						.orderBy(desc(blogPosts.createdAt))
						.limit(limit)
						.offset(offset)
				: await db
						.select()
						.from(blogPosts)
						.where(where)
						.orderBy(desc(blogPosts.createdAt))
						.limit(limit)
						.offset(offset)

			return Response.json(posts, { headers: CACHE_HEADERS })
		}

		if (type === 'blog-authors') {
			if (slug) {
				const author = await db
					.select()
					.from(blogAuthors)
					.where(eq(blogAuthors.slug, slug))
					.limit(1)
				return Response.json(author[0] ?? null, { headers: CACHE_HEADERS })
			}

			const authors = await db
				.select()
				.from(blogAuthors)
				.orderBy(desc(blogAuthors.createdAt))
			return Response.json(authors, { headers: CACHE_HEADERS })
		}

		if (type === 'social') {
			if (platform === 'instagram' || platform === 'linkedin' || platform === 'facebook') {
				const posts = await db
					.select()
					.from(socialPosts)
					.where(eq(socialPosts.platform, platform))
					.orderBy(desc(socialPosts.createdAt))
					.limit(20)
				return Response.json(posts, { headers: CACHE_HEADERS })
			}

			const posts = await db
				.select()
				.from(socialPosts)
				.orderBy(desc(socialPosts.createdAt))
				.limit(20)

			return Response.json(posts, { headers: CACHE_HEADERS })
		}

		return Response.json({ error: 'Invalid content type' }, { status: 400 })
	} catch (err) {
		const url = new URL(request.url)
		console.error(`[GrowthEngine] content route error (${url.search}):`, err)
		return Response.json({ error: 'Internal server error' }, { status: 500 })
	}
}
