import { eq } from 'drizzle-orm'
import { forms, formSubmissions, crmContacts } from '@growth-engine/types/schema'
import type { FormField } from '@growth-engine/types'
import { writeAuditLog } from '@growth-engine/types'
import { getClientDb } from '../db'

/** Best-effort: extract contact fields from form submission and upsert into CRM */
async function tryCreateCrmContact(
	db: ReturnType<typeof getClientDb>,
	submissionId: string,
	data: Record<string, unknown>,
): Promise<void> {
	try {
		const email = (data.email ?? data.Email ?? data.e_mail) as string | undefined
		const firstName = (data.firstName ?? data.first_name ?? data.name ?? data.Name) as string | undefined
		const lastName = (data.lastName ?? data.last_name) as string | undefined
		const phone = (data.phone ?? data.Phone ?? data.telephone) as string | undefined
		const company = (data.company ?? data.Company ?? data.organization) as string | undefined

		if (!email && !firstName) return

		// Deduplicate by email if present
		if (email) {
			const existing = await db
				.select({ id: crmContacts.id })
				.from(crmContacts)
				.where(eq(crmContacts.email, String(email)))
				.limit(1)
			if (existing.length > 0) return
		}

		const parts = firstName ? String(firstName).split(' ') : ['Unknown']
		const first = parts[0] ?? 'Unknown'
		const last = lastName ? String(lastName) : parts.slice(1).join(' ') || 'Unknown'

		await db.insert(crmContacts).values({
			id: crypto.randomUUID(),
			firstName: first,
			lastName: last,
			email: email ? String(email) : null,
			phone: phone ? String(phone) : null,
			company: company ? String(company) : null,
			source: 'form',
			sourceId: submissionId,
			status: 'active',
			createdAt: new Date(),
			updatedAt: new Date(),
		})
	} catch (err) {
		// Best-effort — don't fail the form submission
		console.error('[GrowthEngine] auto-create CRM contact failed:', err)
	}
}

/** Best-effort: notify configured emails about a new form submission */
async function tryNotifyEmails(
	brainApiUrl: string,
	brainApiKey: string,
	formName: string,
	formSlug: string,
	fields: FormField[],
	data: Record<string, unknown>,
	notifyEmails: string[],
): Promise<void> {
	try {
		await fetch(`${brainApiUrl}/api/sdk/forms/notify`, {
			method: 'POST',
			headers: {
				'Content-Type': 'application/json',
				'x-api-key': brainApiKey,
			},
			body: JSON.stringify({
				formName,
				formSlug,
				fields: fields.map((f) => ({ label: f.label, name: f.name })),
				data,
				notifyEmails,
				submittedAt: new Date().toISOString(),
			}),
		})
	} catch (err) {
		console.error('[GrowthEngine] form notify webhook failed:', err)
	}
}

/** Best-effort: send confirmation email to form submitter via Brain webhook */
async function trySendConfirmationEmail(
	brainApiUrl: string,
	brainApiKey: string,
	senderEmail: string,
	formName: string,
	subject?: string,
	message?: string,
): Promise<void> {
	try {
		await fetch(`${brainApiUrl}/api/sdk/forms/confirm`, {
			method: 'POST',
			headers: {
				'Content-Type': 'application/json',
				'x-api-key': brainApiKey,
			},
			body: JSON.stringify({
				to: senderEmail,
				formName,
				subject,
				message,
			}),
		})
	} catch (err) {
		console.error('[GrowthEngine] form confirmation webhook failed:', err)
	}
}

export async function handleForms(
	request: Request,
	tursoUrl: string,
	tursoAuthToken: string,
	brainApiUrl: string,
	brainApiKey: string,
): Promise<Response> {
	try {
		const url = new URL(request.url)
		const action = url.searchParams.get('action')
		const slug = url.searchParams.get('slug')

		const db = getClientDb(tursoUrl, tursoAuthToken)

		if (action === 'list') {
			const rows = await db
				.select()
				.from(forms)
				.where(eq(forms.status, 'active'))

			return Response.json(rows)
		}

		if (action === 'get' && slug) {
			const rows = await db
				.select()
				.from(forms)
				.where(eq(forms.slug, slug))
				.limit(1)

			return Response.json(rows[0] ?? null)
		}

		if (request.method === 'POST' && action === 'submit' && slug) {
			const body = (await request.json()) as { data?: Record<string, unknown> }
			const data = body.data

			if (!data || typeof data !== 'object') {
				return Response.json({ error: 'Missing or invalid data field' }, { status: 400 })
			}

			// Look up the form definition
			const formRows = await db
				.select()
				.from(forms)
				.where(eq(forms.slug, slug))
				.limit(1)

			const form = formRows[0]
			if (!form) {
				return Response.json({ error: 'Form not found' }, { status: 404 })
			}

			// Validate required fields
			const fields = JSON.parse(form.fields) as FormField[]
			const missingFields: string[] = []

			for (const field of fields) {
				if (field.required) {
					const value = data[field.name]
					if (value === undefined || value === null || value === '') {
						missingFields.push(field.label)
					}
				}
			}

			if (missingFields.length > 0) {
				return Response.json(
					{ error: `Missing required fields: ${missingFields.join(', ')}` },
					{ status: 400 },
				)
			}

			const id = crypto.randomUUID()

			await db.insert(formSubmissions).values({
				id,
				formId: form.id,
				data: JSON.stringify(data),
				createdAt: new Date(),
			})

			// Best-effort: auto-create CRM contact from submission
			void tryCreateCrmContact(db, id, data)

			// Best-effort: send email notifications if configured
			const settings = form.settings ? JSON.parse(form.settings) as {
				notifyEmails?: string[]
				sendConfirmationEmail?: boolean
				confirmationEmailSubject?: string
				confirmationEmailMessage?: string
			} : null
			const notifyEmails = settings?.notifyEmails
			if (notifyEmails && notifyEmails.length > 0) {
				void tryNotifyEmails(brainApiUrl, brainApiKey, form.name, slug, fields, data, notifyEmails)
			}

			// Best-effort: send confirmation email to the form submitter
			if (settings?.sendConfirmationEmail) {
				const emailField = fields.find((f) => f.type === 'email')
				const senderEmail = emailField ? String(data[emailField.name] ?? '') : ''
				if (senderEmail) {
					void trySendConfirmationEmail(
						brainApiUrl,
						brainApiKey,
						senderEmail,
						form.name,
						settings.confirmationEmailSubject,
						settings.confirmationEmailMessage,
					)
				}
			}

			void writeAuditLog(db, {
				actor: { type: 'sdk', id: null, email: null },
				action: 'form.submit',
				resourceType: 'form_submission',
				resourceId: id,
				metadata: { formId: form.id, formSlug: slug },
			})

			return Response.json({ ok: true, id })
		}

		return Response.json({ error: 'Invalid action' }, { status: 400 })
	} catch (err) {
		console.error('[GrowthEngine] forms route error:', err)
		return Response.json({ error: 'Internal server error' }, { status: 500 })
	}
}
