import { nanoid } from 'nanoid'
import { analytics } from '@growth-engine/types/schema'
import { getClientDb } from '../db'

export async function handleAnalytics(
	request: Request,
	tursoUrl: string,
	tursoAuthToken: string,
): Promise<Response> {
	if (request.method !== 'POST') {
		return Response.json({ error: 'Method not allowed' }, { status: 405 })
	}

	try {
		const body = (await request.json()) as {
			eventType: string
			page?: string
			sessionId?: string
		}

		if (!body.eventType) {
			return Response.json({ error: 'eventType is required' }, { status: 400 })
		}

		const db = getClientDb(tursoUrl, tursoAuthToken)

		await db.insert(analytics).values({
			id: nanoid(),
			eventType: body.eventType,
			page: body.page ?? null,
			sessionId: body.sessionId ?? null,
			createdAt: new Date(),
		})

		return Response.json({ success: true }, { status: 201 })
	} catch (err) {
		console.error('[GrowthEngine] analytics route error:', err)
		return Response.json({ error: 'Internal server error' }, { status: 500 })
	}
}
