import { sqliteTable, text, integer } from 'drizzle-orm/sqlite-core'

// ─── Blog Authors ───────────────────────────────────────────────────────────

export const blogAuthors = sqliteTable('blog_authors', {
  id: text('id').primaryKey(),
  name: text('name').notNull(),
  slug: text('slug').notNull().unique(),
  email: text('email'),
  bio: text('bio'),
  avatarUrl: text('avatar_url'),
  websiteUrl: text('website_url'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Blog Posts ──────────────────────────────────────────────────────────────

export const blogPosts = sqliteTable('blog_posts', {
  id: text('id').primaryKey(),
  slug: text('slug').notNull().unique(),
  urlPath: text('url_path'),
  title: text('title').notNull(),
  content: text('content').notNull(),
  language: text('language').notNull().default('en'),
  parentPostId: text('parent_post_id'),
  authorId: text('author_id'),
  status: text('status', { enum: ['draft', 'published', 'archived'] })
    .notNull()
    .default('draft'),
  heroImageUrl: text('hero_image_url'),
  seoTitle: text('seo_title'),
  seoDesc: text('seo_desc'),
  publishedAt: integer('published_at', { mode: 'timestamp' }),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Social Posts ────────────────────────────────────────────────────────────

export const socialPosts = sqliteTable('social_posts', {
  id: text('id').primaryKey(),
  platform: text('platform', { enum: ['instagram', 'linkedin', 'facebook'] }).notNull(),
  content: text('content').notNull(),
  scheduledAt: integer('scheduled_at', { mode: 'timestamp' }),
  status: text('status', { enum: ['pending', 'published', 'cancelled'] })
    .notNull()
    .default('pending'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── Business Config ─────────────────────────────────────────────────────────

export const businessConfig = sqliteTable('business_config', {
  id: text('id').primaryKey().default('config'),
  name: text('name'),
  description: text('description'),
  hours: text('hours'),
  contact: text('contact'),
  address: text('address'),
  phone: text('phone'),
  email: text('email'),
  website: text('website'),
  seo: text('seo'),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Variables ──────────────────────────────────────────────────────────

export const variables = sqliteTable('variables', {
  id: text('id').primaryKey(),
  key: text('key').notNull(),
  value: text('value').notNull(),
  note: text('note'),
  scope: text('scope', { enum: ['company', 'user'] }).notNull().default('company'),
  userId: text('user_id'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Analytics ───────────────────────────────────────────────────────────────

export const analytics = sqliteTable('analytics', {
  id: text('id').primaryKey(),
  eventType: text('event_type').notNull(),
  page: text('page'),
  sessionId: text('session_id'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── Forms ──────────────────────────────────────────────────────────────────

export const forms = sqliteTable('forms', {
  id: text('id').primaryKey(),
  slug: text('slug').notNull().unique(),
  name: text('name').notNull(),
  description: text('description'),
  fields: text('fields').notNull(), // JSON array of FormField[]
  settings: text('settings'), // JSON FormSettings object
  status: text('status', { enum: ['active', 'archived'] }).notNull().default('active'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Form Submissions ──────────────────────────────────────────────────────

export const formSubmissions = sqliteTable('form_submissions', {
  id: text('id').primaryKey(),
  formId: text('form_id').notNull(),
  data: text('data').notNull(), // JSON object of field values
  metadata: text('metadata'), // JSON: IP, user agent, referrer
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── Files ──────────────────────────────────────────────────────────────────

export const files = sqliteTable('files', {
  id: text('id').primaryKey(),
  name: text('name').notNull(),
  gcsPath: text('gcs_path').notNull(),
  visibility: text('visibility', { enum: ['public', 'private', 'password'] })
    .notNull()
    .default('private'),
  passwordHash: text('password_hash'),
  contentType: text('content_type').notNull(),
  sizeBytes: integer('size_bytes').notNull(),
  category: text('category', { enum: ['blog', 'brand', 'document', 'general'] })
    .notNull()
    .default('general'),
  uploadedBy: text('uploaded_by'),
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
  updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Organizations ────────────────────────────────────────────────────

export const crmOrganizations = sqliteTable('crm_organizations', {
	id: text('id').primaryKey(),
	name: text('name').notNull(),
	website: text('website'),
	industry: text('industry'),
	size: text('size', { enum: ['1-10', '11-50', '51-200', '201-500', '500+'] }),
	phone: text('phone'),
	address: text('address'),
	city: text('city'),
	state: text('state'),
	country: text('country'),
	notes: text('notes'),
	customFields: text('custom_fields'), // JSON Record<string, unknown>
	status: text('status', { enum: ['active', 'archived'] }).notNull().default('active'),
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
	updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Contacts ──────────────────────────────────────────────────────────

export const crmContacts = sqliteTable('crm_contacts', {
	id: text('id').primaryKey(),
	firstName: text('first_name').notNull(),
	lastName: text('last_name').notNull(),
	email: text('email'),
	phone: text('phone'),
	company: text('company'),
	organizationId: text('organization_id'),
	jobTitle: text('job_title'),
	source: text('source', { enum: ['form', 'manual', 'import', 'sdk', 'lead_finder'] })
		.notNull()
		.default('manual'),
	sourceId: text('source_id'),
	ownerId: text('owner_id'),
	tags: text('tags'), // JSON string[]
	notes: text('notes'),
	status: text('status', { enum: ['active', 'archived'] }).notNull().default('active'),
	customFields: text('custom_fields'), // JSON Record<string, unknown>
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
	updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Pipeline Stages ───────────────────────────────────────────────────

export const crmPipelineStages = sqliteTable('crm_pipeline_stages', {
	id: text('id').primaryKey(),
	name: text('name').notNull(),
	order: integer('order').notNull(),
	color: text('color'),
	isDefault: integer('is_default', { mode: 'boolean' }).notNull().default(false),
	isClosed: integer('is_closed', { mode: 'boolean' }).notNull().default(false),
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Deals ─────────────────────────────────────────────────────────────

export const crmDeals = sqliteTable('crm_deals', {
	id: text('id').primaryKey(),
	title: text('title').notNull(),
	contactId: text('contact_id').notNull(),
	stageId: text('stage_id').notNull(),
	value: integer('value'), // in cents
	currency: text('currency').notNull().default('USD'),
	expectedCloseDate: integer('expected_close_date', { mode: 'timestamp' }),
	closedAt: integer('closed_at', { mode: 'timestamp' }),
	ownerId: text('owner_id'),
	tags: text('tags'), // JSON string[]
	notes: text('notes'),
	status: text('status', { enum: ['open', 'won', 'lost'] }).notNull().default('open'),
	customFields: text('custom_fields'), // JSON Record<string, unknown>
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
	updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Activities ────────────────────────────────────────────────────────

export const crmActivities = sqliteTable('crm_activities', {
	id: text('id').primaryKey(),
	type: text('type', { enum: ['call', 'email', 'email_received', 'meeting', 'note', 'task', 'form_submission', 'pipeline_change', 'status_change', 'deal_created', 'website_visit'] }).notNull(),
	title: text('title').notNull(),
	description: text('description'),
	contactId: text('contact_id'),
	dealId: text('deal_id'),
	userId: text('user_id'),
	assigneeId: text('assignee_id'),
	dueDate: integer('due_date', { mode: 'timestamp' }),
	completedAt: integer('completed_at', { mode: 'timestamp' }),
	metadata: text('metadata'), // JSON Record<string, unknown>
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Deal Stage History ────────────────────────────────────────────────

export const crmDealStageHistory = sqliteTable('crm_deal_stage_history', {
	id: text('id').primaryKey(),
	dealId: text('deal_id').notNull(),
	fromStageId: text('from_stage_id'),
	toStageId: text('to_stage_id').notNull(),
	changedBy: text('changed_by'),
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Pipelines ────────────────────────────────────────────────────────

export const crmPipelines = sqliteTable('crm_pipelines', {
	id: text('id').primaryKey(),
	name: text('name').notNull(),
	description: text('description'),
	inputSources: text('input_sources').notNull().default('[]'), // JSON PipelineInputSource[]
	steps: text('steps').notNull().default('[]'), // JSON PipelineStep[]
	apiKeys: text('api_keys').notNull().default('[]'), // JSON PipelineApiKey[]
	status: text('status', { enum: ['active', 'archived'] }).notNull().default('active'),
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
	updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── CRM: Pipeline Entries ─────────────────────────────────────────────────

export const crmPipelineEntries = sqliteTable('crm_pipeline_entries', {
	id: text('id').primaryKey(),
	pipelineId: text('pipeline_id').notNull(),
	contactId: text('contact_id').notNull(),
	contactName: text('contact_name').notNull(),
	contactEmail: text('contact_email'),
	contactCompany: text('contact_company'),
	currentStepIndex: integer('current_step_index').notNull().default(0),
	stepStatuses: text('step_statuses').notNull().default('[]'), // JSON PipelineEntryStep[]
	status: text('status', { enum: ['active', 'completed', 'dropped'] }).notNull().default('active'),
	createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
	updatedAt: integer('updated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Schema Version ─────────────────────────────────────────────────────────

export const schemaVersion = sqliteTable('_schema_version', {
  id: text('id').primaryKey().default('version'),
  version: integer('version').notNull(),
  migratedAt: integer('migrated_at', { mode: 'timestamp' }).notNull(),
})

// ─── Audit Logs ──────────────────────────────────────────────────────────────

export const auditLogs = sqliteTable('audit_logs', {
  id: text('id').primaryKey(),
  actorType: text('actor_type', { enum: ['user', 'worker', 'sdk', 'system'] }).notNull(),
  actorId: text('actor_id'),
  actorEmail: text('actor_email'),
  action: text('action').notNull(),
  resourceType: text('resource_type').notNull(),
  resourceId: text('resource_id'),
  traceId: text('trace_id'),
  metadata: text('metadata'), // JSON Record<string, unknown>
  createdAt: integer('created_at', { mode: 'timestamp' }).notNull(),
})
